'use strict';
const { test } = require('node:test');
const assert = require('node:assert');
const os = require('node:os');
const fs = require('node:fs');
const path = require('node:path');
const crypto = require('node:crypto');
const sharp = require('sharp');

const {
  HD_SCHEMA_VERSION, SURFACE_CHANNELS, courseFingerprint,
  validateManifest, decodeTerrainF32, validateBundleDirectory, resolveAssetPath,
} = require('../lib/hd-bundle');

const FIXTURES = path.join(__dirname, 'fixtures', 'hd-course');
const sha256 = (buf) => crypto.createHash('sha256').update(buf).digest('hex');
const codeIs = (c) => (e) => e && e.code === c;

// Build a complete, valid bundle on disk in a fresh temp dir. Images are real
// (generated by sharp); terrain is little-endian Float32.
async function makeBundle() {
  const dir = fs.mkdtempSync(path.join(os.tmpdir(), 'hd-bundle-'));
  const holeDir = path.join(dir, 'holes', '01');
  fs.mkdirSync(holeDir, { recursive: true });

  const nx = 4, ny = 4, cellM = 5;
  const f32 = Buffer.alloc(nx * ny * 4);
  for (let i = 0; i < nx * ny; i++) f32.writeFloatLE(i * 0.1, i * 4);
  fs.writeFileSync(path.join(holeDir, 'terrain.f32'), f32);

  const ortho = await sharp({ create: { width: 8, height: 8, channels: 3, background: { r: 10, g: 120, b: 40 } } }).webp().toBuffer();
  fs.writeFileSync(path.join(holeDir, 'orthophoto.webp'), ortho);
  const surfaces = await sharp({ create: { width: 4, height: 4, channels: 4, background: { r: 255, g: 0, b: 0, alpha: 1 } } }).png().toBuffer();
  fs.writeFileSync(path.join(holeDir, 'surfaces.png'), surfaces);
  const coverage = await sharp({ create: { width: 4, height: 4, channels: 4, background: { r: 0, g: 255, b: 0, alpha: 1 } } }).png().toBuffer();
  fs.writeFileSync(path.join(holeDir, 'coverage.png'), coverage);

  fs.writeFileSync(path.join(dir, 'provenance.json'), JSON.stringify({ source: 'synthetic-test' }));

  const course = JSON.parse(fs.readFileSync(path.join(FIXTURES, 'course.json'), 'utf8'));
  const manifest = {
    schemaVersion: 1,
    compilerVersion: '0.1.0',
    course: { name: course.name, fingerprint: courseFingerprint(course) },
    hole: 1,
    bounds: { minX: 0, minY: 0, maxX: (nx - 1) * cellM, maxY: (ny - 1) * cellM },
    terrain: { file: 'holes/01/terrain.f32', nx, ny, cellM, baseM: 12.5, byteOrder: 'LE', sha256: sha256(f32), bytes: f32.length },
    image: { file: 'holes/01/orthophoto.webp', width: 8, height: 8, colorSpace: 'srgb', sha256: sha256(ortho), bytes: ortho.length },
    surfaces: { file: 'holes/01/surfaces.png', width: 4, height: 4, sha256: sha256(surfaces), bytes: surfaces.length },
    coverage: { file: 'holes/01/coverage.png', width: 4, height: 4, sha256: sha256(coverage), bytes: coverage.length },
  };
  fs.writeFileSync(path.join(dir, 'manifest.json'), JSON.stringify(manifest, null, 2));
  return { dir, holeDir, manifest };
}

const writeManifest = (dir, m) => fs.writeFileSync(path.join(dir, 'manifest.json'), JSON.stringify(m, null, 2));

test('SURFACE_CHANNELS encodes the schema-v1 mask packing', () => {
  assert.equal(HD_SCHEMA_VERSION, 1);
  assert.deepEqual(SURFACE_CHANNELS, {
    surfaces: { r: 'fairway', g: 'green', b: 'tee', a: 'bunker' },
    coverage: { r: 'validity', g: 'water' },
  });
});

test('courseFingerprint matches the ESM compiler implementation', async () => {
  const { canonicalCourseFingerprint } = await import('../tools/hd-course/course-source.mjs');
  const course = JSON.parse(fs.readFileSync(path.join(FIXTURES, 'course.json'), 'utf8'));
  assert.match(courseFingerprint(course), /^[a-f0-9]{64}$/);
  assert.equal(courseFingerprint(course), canonicalCourseFingerprint(course));
});

test('decodeTerrainF32 decodes little-endian and rejects bad input', () => {
  const buf = Buffer.alloc(16 * 4);
  for (let i = 0; i < 16; i++) buf.writeFloatLE(i + 0.25, i * 4);
  const out = decodeTerrainF32(buf, 4, 4);
  assert.equal(out.length, 16);
  assert.equal(out[3], 3.25);
  assert.throws(() => decodeTerrainF32(Buffer.alloc(10), 4, 4), codeIs('HD_TERRAIN_LENGTH'));
  const nan = Buffer.alloc(16); nan.writeFloatLE(NaN, 0);
  assert.throws(() => decodeTerrainF32(nan, 2, 2), codeIs('HD_TERRAIN_NONFINITE'));
});

test('validateManifest rejects an unsupported schema version', () => {
  assert.throws(() => validateManifest({ schemaVersion: 2 }), codeIs('HD_SCHEMA_VERSION'));
});

test('resolveAssetPath blocks traversal out of the bundle', () => {
  const root = fs.mkdtempSync(path.join(os.tmpdir(), 'hd-asset-'));
  assert.equal(resolveAssetPath(root, 'holes/01/terrain.f32'), path.join(root, 'holes', '01', 'terrain.f32'));
  assert.throws(() => resolveAssetPath(root, '../escape'), codeIs('HD_PATH_TRAVERSAL'));
  assert.throws(() => resolveAssetPath(root, 'holes/../../escape'), codeIs('HD_PATH_TRAVERSAL'));
});

test('a complete bundle validates', async () => {
  const { dir, manifest } = await makeBundle();
  const res = validateBundleDirectory(dir);
  assert.equal(res.status, 'valid');
  assert.equal(res.descriptor.hole, 1);
  assert.equal(res.descriptor.terrain.nx, manifest.terrain.nx);
});

test('an absent bundle reports absent, not rejected', () => {
  const dir = fs.mkdtempSync(path.join(os.tmpdir(), 'hd-empty-'));
  assert.equal(validateBundleDirectory(dir).status, 'absent');
});

test('a tampered terrain payload is rejected on hash mismatch', async () => {
  const { dir, holeDir } = await makeBundle();
  const f = path.join(holeDir, 'terrain.f32');
  const buf = fs.readFileSync(f); buf.writeFloatLE(999, 0); fs.writeFileSync(f, buf);
  const res = validateBundleDirectory(dir);
  assert.equal(res.status, 'rejected');
  assert.equal(res.code, 'HD_HASH_MISMATCH');
});

test('a truncated asset is rejected on size mismatch', async () => {
  const { dir, holeDir } = await makeBundle();
  fs.writeFileSync(path.join(holeDir, 'terrain.f32'), Buffer.alloc(8));
  assert.equal(validateBundleDirectory(dir).code, 'HD_SIZE_MISMATCH');
});

test('an unexpected file in the bundle is rejected', async () => {
  const { dir, holeDir } = await makeBundle();
  fs.writeFileSync(path.join(holeDir, 'stowaway.bin'), 'x');
  assert.equal(validateBundleDirectory(dir).code, 'HD_UNEXPECTED_FILE');
});

test('an image whose real dimensions disagree with the manifest is rejected', async () => {
  const { dir, manifest } = await makeBundle();
  manifest.image.width = 9; // real webp is 8 wide
  writeManifest(dir, manifest);
  // size+hash still match (manifest dims are metadata), so this exercises the header check.
  assert.equal(validateBundleDirectory(dir).code, 'HD_IMAGE_DIMENSION');
});

test('terrain bounds inconsistent with grid spacing are rejected', async () => {
  const { dir, manifest } = await makeBundle();
  manifest.bounds.maxX = 999;
  writeManifest(dir, manifest);
  assert.equal(validateBundleDirectory(dir).code, 'HD_GRID_MISMATCH');
});
